export default function Message({msg}){

  const isUser = msg.type==="user";

  return(

    <div style={{
      display:"flex",
      justifyContent:isUser?"flex-end":"flex-start"
    }}>

      <div style={{
        padding:"12px",
        margin:"10px",
        borderRadius:"10px",
        maxWidth:"60%",
        background:isUser?"#6366f1":"#ffffff",
        color:isUser?"white":"black",
        boxShadow:"0px 2px 6px rgba(0,0,0,0.15)"
      }}>

        {msg.text}

      </div>

    </div>

  );

}
